.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.257') AND fhirpath_text(claim_principal_procedure(_c.resource, fhirpath_text(QualifyingEncounterICU.resource, 'id')), 'procedureReference.reference') LIKE '%/' || fhirpath_text(_pr.resource, 'id')))) OR EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Claim') AS _c WHERE _c.patient_id = QualifyingEncounterICU.patient_id AND fhirpath_text(_c.resource, 'status') = 'active' AND fhirpath_text(_c.resource, 'use') = 'claim' AND claim_principal_procedure(_c.resource, fhirpath_text(QualifyingEncounterICU.resource, 'id')) IS NOT NULL AND (in_valueset(claim_principal_procedure(_c.resource, fhirpath_text(QualifyingEncounterICU.resource, 'id')), 'procedureCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.258') OR EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Procedure') AS _pr WHERE _pr.patient_id = QualifyingEncounterICU.patient_id AND in_valueset(_pr.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.258') AND fhirpath_text(claim_principal_procedure(_c.resource, fhirpath_text(QualifyingEncounterICU.resource, 'id')), 'procedureReference.reference') LIKE '%/' || fhirpath_text(_pr.resource, 'id')))) OR EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Claim') AS _c WHERE _c.patient_id = QualifyingEncounterICU.patient_id AND fhirpath_text(_c.resource, 'status') = 'active' AND fhirpath_text(_c.resource, 'use') = 'claim' AND claim_principal_procedure(_c.resource, fhirpath_text(QualifyingEncounterICU.resource, 'id')) IS NOT NULL AND (in_valueset(claim_principal_procedure(_c.resource, fhirpath_text(QualifyingEncounterICU.resource, 'id')), 'procedureCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.259') OR EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient