),
"Encounter With ICU Location And Encounter Less Than 2 Days" AS (
SELECT * FROM "Encounter With ICU Location" AS QualifyingEncounterICU WHERE differenceInDays(CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS VARCHAR), CAST(intervalEnd(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS VARCHAR)) < 2
),
