 COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = FactorXaMedication.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = FactorXaMedication.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = FactorXaMedication.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = FactorXaMedication.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS VARCHAR), CAST(dateAddQuantity(CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '