tart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = FactorXaMedication.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = FactorXaMedication.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS TIMESTAMP) + INTERVAL '1 day' AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(FactorXaMedication.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FactorXaMedication.resource, 'effective')), '{') THEN fhirpath_text(FactorXaMedication.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(FactorXaMedication.resource, 'effective'), fhirpath_text(FactorXaMedication.resource, 'effective'), TRUE, TRUE) END) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), CAST(dateAddQuantity(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), CAST(dateAddQuantity(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), CAST(dateAddQuantity(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS DATE)) AND AnesthesiaProcedure.patient_id = QualifyingEncounterICU.patient_id AND FactorXaMedication.patient_id = QualifyingEncounterICU.patient_id)
),
"Encounter With Prior Or Present Diagnosis Of Atrial Fibrillation Or Prior Diagnosis Of VTE" AS (
(SELECT patient_id, resource FROM "Encounter With ICU Location" AS QualifyingEncounterICU WHERE EXISTS (SELECT 1 FROM "Condition: Atrial Fibrillation or Flutter (qicore-condition-problems-health-concerns)" AS AtrialFibrillation WHERE (NOT (fhirpath_text(AtrialFibrillation.resource, 'verificationStatus') IS NOT NULL) OR NOT fhirpath_bool(AtrialFibrillation.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''refuted'').exists()') AND NOT fhirpath_bool(AtrialFibrillation.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''entered-in-error'').exists()')) AND CAST(intervalStart(CASE WHEN fhirpath_text(AtrialFibrillation.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AtrialFibrillation.resource, 'onset')), '{') THEN fhirpath_text(AtrialFibrillation.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(AtrialFibrillation.resource, 'onset'), fhirpath_text(AtrialFibrillation.resource, 'onset'), TRUE, TRUE) END) AS DATE) <= CAST(intervalEnd(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS DATE) AND AtrialFibrillation.patient_id = QualifyingEncounterICU.patient_id)) UNION (SELECT patient_id, resource FROM "Encounter With ICU Location" AS QualifyingEncounterICU WHERE EXISTS (SELECT 1 FROM (SELECT unnest((SELECT list(CASE WHEN (SELECT COUNT(*) FROM (SELECT patient_id, resource FROM "Condition (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition (qicore-condition-problems-health-concerns)") AS C WHERE fhirpath_text(C.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_D, 'reference'), '/'), -1) AND C.patient_id = QualifyingEncounterICU.patient_id) = 1 THEN (SELECT resource FROM (SELECT patient_id, resource FROM "Condition (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition (qicore-condition-problems-health-concerns)") AS C WHERE fhirpath_text(C.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_D, 'reference'), '/'), -1) AND C.patient_id = QualifyingEncounterICU.patient_id LIMIT 1) ELSE NULL END) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'reasonReference'), '["VARCHAR"]')) AS _lt_D) AS _lt_unnest)) AS _ivr) AS _ivt WHERE in_valueset(_ivr, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.202')) OR in_valueset(QualifyingEncounterICU.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.202')) UNION (SELECT patient_id, resource FROM "Encounter With ICU Location" AS QualifyingEncounterICU WHERE EXISTS (SELECT 1 FROM "Condition: Venous Thromboembolism (qicore-condition-problems-health-concerns)" AS VTEDiagnosis WHERE (fhirpath_bool(VTEDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''inactive'').exists()') OR fhirpath_bool(VTEDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''remission'').exists()') OR fhirpath_bool(VTEDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''resolved'').exists()')) AND (NOT (fhirpath_text(VTEDiagnosis.resource, 'verificationStatus') IS NOT NULL) OR NOT fhirpath_bool(VTEDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''refuted'').exists()') AND NOT fhirpath_bool(VTEDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''entered-in-error'').exists()')) AND intervalBefore(CASE WHEN fhirpath_text(VTEDiagnosis.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTEDiagnosis.resource, 'onset')), '{') THEN fhirpath_text(VTEDiagnosis.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(VTEDiagnosis.resource, 'onset'), fhirpath_text(VTEDiagnosis.resource, 'onset'), TRUE, TRUE) END, intervalFromBounds(CAST(CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS VARCHAR) AS VARCHAR), CAST(CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS VARCHAR) AS VARCHAR), TRUE, TRUE)) AND VTEDiagnosis.patient_id = QualifyingEncounterICU.patient_id))
),
"Encounter With Prior Or Present Procedure Of Hip Or Knee Replacement Surgery" AS (
SELECT * FROM "Encounter With ICU Location" AS QualifyingEncounterICU WHERE EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Procedure: Hip Replacement Surgery" UNION SELECT patient_id, resource FROM "Procedure: Knee Replacement Surgery") AS HipKneeProcedure WHERE fhirpath_text(HipKneeProcedure.resource, 'status') = 'completed' AND CAST(intervalStart(CASE WHEN fhirpath_text(HipKneeProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HipKneeProcedure.resource, 'performed')), '{') THEN fhirpath_text(HipKneeProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HipKneeProcedure.resource, 'performed'), fhirpath_text(HipKneeProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= CAST(intervalEnd(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS DATE) AND HipKneeProcedure.patient_id = QualifyingEncounterICU.patient_id)
),
"Initial Population" AS (
SELECT * FROM "VTE.Encounter With Age Range And Without VTE Diagnosis Or Obstetrical Conditions"
),
"Intervention Comfort Measures" AS (
(SELECT patient_id, resource FROM "ServiceRequest: Comfort Measures" AS InterventionRequest WHERE array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], InterventionRequest.intent) AND array_contains(['active', 'on-hold', 'completed'], InterventionRequest.status)) UNION (SELECT patient_id, resource FROM "Procedure: Comfort Measures" AS InterventionPerformed WHERE array_contains(['completed', 'in-progress'], InterventionPerformed.status))
),
"Encounter With Intervention Comfort Measures From Day Of Start Of Hospitalization To Day After First ICU Stay" AS (
SELECT * FROM "Encounter With ICU Location" AS QualifyingEncounterICU WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Intervention Comfort Measures") AS ComfortMeasure WHERE CAST(COALESCE(intervalStart(CASE WHEN fhirpath_text(ComfortMeasure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ComfortMeasure.resource, 'performed')), '{') THEN fhirpath_text(ComfortMeasure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ComfortMeasure.resource, 'performed'), fhirpath_text(ComfortMeasure.resource, 'performed'), TRUE, TRUE) END), fhirpath_text(ComfortMeasure.resource, 'authoredOn')) AS DATE) >= CAST(intervalStart(intervalFromBounds(COALESCE(intervalStart(fhirpath_text((SELECT resource FROM "Encounter: Emergency Department Visit" AS LastED WHERE fhirpath_text(LastED.resource, 'status') = 'finished' AND CAST(COALESCE(intervalStart(fhirpath_text((SELECT resource FROM "Encounter: Observation Services" AS LastObs WHERE fhirpath_text(LastObs.resource, 'status') = 'finished' AND CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 hour' <= CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) AND LastObs.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastObs.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastObs.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period'))) AS TIMESTAMP) - INTERVAL '1 hour' <= CAST(intervalEnd(fhirpath_text(LastED.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(LastED.resource, 'period')) AS TIMESTAMP) <= CAST(COALESCE(intervalStart(fhirpath_text((SELECT resource FROM "Encounter: Observation Services" AS LastObs WHERE fhirpath_text(LastObs.resource, 'status') = 'finished' AND CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 hour' <= CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) AND LastObs.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastObs.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastObs.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period'))) AS TIMESTAMP) AND LastED.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastED.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastED.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), COALESCE(intervalStart(fhirpath_text((SELECT resource FROM "Encounter: Observation Services" AS LastObs WHERE fhirpath_text(LastObs.resource, 'status') = 'finished' AND CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 hour' <= CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) AND LastObs.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastObs.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastObs.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')))), CAST(intervalEnd(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE) AND CAST(COALESCE(intervalStart(CASE WHEN fhirpath_text(ComfortMeasure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ComfortMeasure.resource, 'performed')), '{') THEN fhirpath_text(ComfortMeasure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ComfortMeasure.resource, 'performed'), fhirpath_text(ComfortMeasure.resource, 'performed'), TRUE, TRUE) END), fhirpath_text(ComfortMeasure.resource, 'authoredOn')) AS DATE) <= CAST(dateAddQuantity(CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = ComfortMeasure.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = ComfortMeasure.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND ComfortMeasure.patient_id = QualifyingEncounterICU.patient_id)
),
"Encounter With Intervention Comfort Measures On Day Of Or Day After Procedure" AS (
SELECT QualifyingEncounterICU.patient_id, CAST(QualifyingEncounterICU.resource AS VARCHAR) AS resource FROM "Encounter With ICU Location" AS QualifyingEncounterICU CROSS JOIN "Procedure: General or Neuraxial Anesthesia" AS AnesthesiaProcedure CROSS JOIN (SELECT * FROM "Intervention Comfort Measures") AS ComfortMeasure WHERE AnesthesiaProcedure.status = 'completed' AND CAST(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AS DATE) = CAST(CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = ComfortMeasure.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = ComfortMeasure.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS TIMESTAMP) + INTERVAL '1 day' AS DATE) AND CAST(COALESCE(intervalStart(CASE WHEN fhirpath_text(ComfortMeasure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ComfortMeasure.resource, 'performed')), '{') THEN fhirpath_text(ComfortMeasure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ComfortMeasure.resource, 'performed'), fhirpath_text(ComfortMeasure.resource, 'performed'), TRUE, TRUE) END), fhirpath_text(ComfortMeasure.resource, 'authoredOn')) AS DATE) >= CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND CAST(COALESCE(intervalStart(CASE WHEN fhirpath_text(ComfortMeasure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ComfortMeasure.resource, 'performed')), '{') THEN fhirpath_text(ComfortMeasure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ComfortMeasure.resource, 'performed'), fhirpath_text(ComfortMeasure.resource, 'performed'), TRUE, TRUE) END), fhirpath_text(ComfortMeasure.resource, 'authoredOn')) AS DATE) <= CAST(dateAddQuantity(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND AnesthesiaProcedure.patient_id = QualifyingEncounterICU.patient_id AND ComfortMeasure.patient_id = QualifyingEncounterICU.patient_id
),
"Denominator Exclusions" AS (
(SELECT patient_id, resource FROM "Encounter With ICU Location And Encounter Less Than 2 Days") UNION (SELECT patient_id, resource FROM "Encounter With First ICU Stay With Principal Procedure Of Selected Surgery") UNION (SELECT patient_id, resource FROM "Encounter With Intervention Comfort Measures From Day Of Start Of Hospitalization To Day After First ICU Stay") UNION (SELECT patient_id, resource FROM "Encounter With Intervention Comfort Measures On Day Of Or Day After Procedure")
),
"Low Risk Indicator For VTE" AS (
(SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('id', fhirpath_text(VTERiskAssessment.resource, 'id'), 'LowRiskDatetime', CASE WHEN NOT (intervalStart(CASE WHEN fhirpath_text(VTERiskAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTERiskAssessment.resource, 'effective')), '{') THEN fhirpath_text(VTERiskAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VTERiskAssessment.resource, 'effective'), fhirpath_text(VTERiskAssessment.resource, 'effective'), TRUE, TRUE) END) IS NULL OR intervalStart(CASE WHEN fhirpath_text(VTERiskAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTERiskAssessment.resource, 'effective')), '{') THEN fhirpath_text(VTERiskAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VTERiskAssessment.resource, 'effective'), fhirpath_text(VTERiskAssessment.resource, 'effective'), TRUE, TRUE) END) = '0001-01-01 00:00:00') THEN intervalStart(CASE WHEN fhirpath_text(VTERiskAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTERiskAssessment.resource, 'effective')), '{') THEN fhirpath_text(VTERiskAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VTERiskAssessment.resource, 'effective'), fhirpath_text(VTERiskAssessment.resource, 'effective'), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN fhirpath_text(VTERiskAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTERiskAssessment.resource, 'effective')), '{') THEN fhirpath_text(VTERiskAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VTERiskAssessment.resource, 'effective'), fhirpath_text(VTERiskAssessment.resource, 'effective'), TRUE, TRUE) END) END) AS _resource_data FROM "Observation: Risk for venous thromboembolism" AS VTERiskAssessment WHERE in_valueset(VTERiskAssessment.resource, 'value', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.400') AND array_contains(['final', 'amended', 'corrected'], VTERiskAssessment.status)) AS _inner) UNION (SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('id', fhirpath_text(INRLabTest.resource, 'id'), 'LowRiskDatetime', fhirpath_text(INRLabTest.resource, 'issued')) AS _resource_data FROM "Observation: INR" AS INRLabTest WHERE quantity_value(parse_quantity(INRLabTest.value)) > 3.0 AND array_contains(['final', 'amended', 'corrected'], INRLabTest.status)) AS _inner) UNION (SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('id', fhirpath_text(AnticoagulantMedication.resource, 'id'), 'LowRiskDatetime', intervalStart(CASE WHEN fhirpath_text(AnticoagulantMedication.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnticoagulantMedication.resource, 'effective')), '{') THEN fhirpath_text(AnticoagulantMedication.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(AnticoagulantMedication.resource, 'effective'), fhirpath_text(AnticoagulantMedication.resource, 'effective'), TRUE, TRUE) END)) AS _resource_data FROM ((SELECT patient_id, resource FROM "MedicationAdministration: Unfractionated Heparin" AS UnfractionatedHeparin WHERE in_valueset(UnfractionatedHeparin.resource, 'dosage.route', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.222')) UNION SELECT patient_id, resource FROM "MedicationAdministration: Direct Thrombin Inhibitor" UNION SELECT patient_id, resource FROM "MedicationAdministration: Glycoprotein IIb IIIa Inhibitors") AS AnticoagulantMedication WHERE fhirpath_text(AnticoagulantMedication.resource, 'status') = 'completed') AS _inner)
),
"Low Risk For VTE Or Anticoagulant Administered From Day Of Start Of Hospitalization To Day After First ICU Stay" AS (
SELECT * FROM "Encounter With ICU Location" AS QualifyingEncounterICU WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Low Risk Indicator For VTE") AS LowRiskForVTE WHERE CAST(fhirpath_text(LowRiskForVTE.resource, 'LowRiskDatetime') AS DATE) >= CAST(intervalStart(intervalFromBounds(COALESCE(intervalStart(fhirpath_text((SELECT resource FROM "Encounter: Emergency Department Visit" AS LastED WHERE fhirpath_text(LastED.resource, 'status') = 'finished' AND CAST(COALESCE(intervalStart(fhirpath_text((SELECT resource FROM "Encounter: Observation Services" AS LastObs WHERE fhirpath_text(LastObs.resource, 'status') = 'finished' AND CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 hour' <= CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) AND LastObs.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastObs.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastObs.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period'))) AS TIMESTAMP) - INTERVAL '1 hour' <= CAST(intervalEnd(fhirpath_text(LastED.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(LastED.resource, 'period')) AS TIMESTAMP) <= CAST(COALESCE(intervalStart(fhirpath_text((SELECT resource FROM "Encounter: Observation Services" AS LastObs WHERE fhirpath_text(LastObs.resource, 'status') = 'finished' AND CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 hour' <= CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) AND LastObs.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastObs.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastObs.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period'))) AS TIMESTAMP) AND LastED.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastED.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastED.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), COALESCE(intervalStart(fhirpath_text((SELECT resource FROM "Encounter: Observation Services" AS LastObs WHERE fhirpath_text(LastObs.resource, 'status') = 'finished' AND CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 hour' <= CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) AND LastObs.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastObs.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastObs.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')))), CAST(intervalEnd(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE) AND CAST(fhirpath_text(LowRiskForVTE.resource, 'LowRiskDatetime') AS DATE) <= CAST(dateAddQuantity(CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = LowRiskForVTE.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = LowRiskForVTE.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND LowRiskForVTE.patient_id = QualifyingEncounterICU.patient_id)
),
"Low Risk For VTE Or Anticoagulant Administered On Day Of Or Day After Procedure" AS (
