HEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND CAST(fhirpath_text(PatientRefusal.resource, 'authoredOn') AS DATE) <= CAST(dateAddQuantity(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND AnesthesiaProcedure.patient_id = QualifyingEncounterICU.patient_id AND PatientRefusal.patient_id = QualifyingEncounterICU.patient_id
),
"Encounter With No VTE Prophylaxis Due To Patient Refusal" AS (
(SELECT patient_id, resource FROM "No VTE Prophylaxis Due To Patient Refusal From Day Of Start Of Hospitalization To Day After First ICU Stay") UNION (SELECT patient_id, resource FROM "No VTE Prophylaxis Due To Patient Refusal On Day Of Or Day After Procedure")
),
"No VTE Prophylaxis Medication Due To Medical Reason From Day Of Start Of Hospitalization To Day After First ICU Stay" AS (
