) AND CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) AND LastObs.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastObs.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastObs.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period'))) AS TIMESTAMP) AND LastED.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastED.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastED.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), COALESCE(intervalStart(fhirpath_text((SELECT resource FROM "Encounter: Observation Services" AS LastObs WHERE fhirpath_text(LastObs.resource, 'status') = 'finished' AND CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 hour' <= CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(LastObs.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS TIMESTAMP) AND LastObs.patient_id = QualifyingEncounterICU.patient_id ORDER BY intervalEnd(fhirpath_text(LastObs.resource, 'period')) DESC NULLS FIRST, json_extract_string(LastObs.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period')), intervalStart(fhirpath_text(QualifyingEncounterICU.resource, 'period')))), CAST(intervalEnd(fhirpath_text(QualifyingEncounterICU.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE) AND CAST(fhirpath_text(NoVTEMedication.resource, 'authoredOn') AS DATE) <= CAST(dateAddQuantity(CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = NoVTEMedication.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = NoVTEMedication.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND NoVTEMedication.patient_id = QualifyingEncounterICU.patient_id)
),
"No VTE Prophylaxis Medication Due To Medical Reason On Day Of Or Day After Procedure" AS (
SELECT QualifyingEncounterICU.patient_id, CAST(QualifyingEncounterICU.resource AS VARCHAR) AS resource FROM "Encounter With ICU Location" AS QualifyingEncounterICU CROSS JOIN "Procedure: General or Neuraxial Anesthesia" AS AnesthesiaProcedure CROSS JOIN (SELECT * FROM "No VTE Prophylaxis Medication Administered Or Ordered") AS NoVTEMedication WHERE in_valueset(NoVTEMedication.resource, 'medicationStatusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.473') AND AnesthesiaProcedure.status = 'completed' AND CAST(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AS DATE) = CAST(CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = NoVTEMedication.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = NoVTEMedication.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS TIMESTAMP) + INTERVAL '1 day' AS DATE) AND CAST(fhirpath_text(NoVTEMedication.resource, 'authoredOn') AS DATE) >= CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND CAST(fhirpath_text(NoVTEMedication.resource, 'authoredOn') AS DATE) <= CAST(dateAddQuantity(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND AnesthesiaProcedure.patient_id = QualifyingEncounterICU.patient_id AND NoVTEMedication.patient_id = QualifyingEncounterICU.patient_id
),
"Encounter With No VTE Prophylaxis Due To Medical Reason" AS (
((SELECT patient_id, resource FROM "No VTE Prophylaxis Medication Due To Medical Reason From Day Of Start Of Hospitalization To Day After First ICU Stay") INTERSECT (SELECT patient_id, resource FROM "No Mechanical VTE Prophylaxis Due To Medical Reason From Day Of Start Of Hospitalization To Day After First ICU Stay")) UNION ((SELECT patient_id, resource FROM "No VTE Prophylaxis Medication Due To Medical Reason On Day Of Or Day After Procedure") INTERSECT (SELECT patient_id, resource FROM "No Mechanical VTE Prophylaxis Due To Medical Reason On Day Of Or Day After Procedure"))
),
"Pharmacological Or Mechanical VTE Prophylaxis Received" AS (
(SELECT patient_id, resource FROM "MedicationAdministration: Low Dose Unfractionated Heparin for VTE Prophylaxis" AS VTEMedication WHERE fhirpath_text(VTEMedication.resource, 'status') = 'completed' AND in_valueset(VTEMedication.resource, 'dosage.route', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.223')) UNION (SELECT patient_id, resource FROM "MedicationAdministration: Low Molecular Weight Heparin for VTE Prophylaxis" AS LMWH WHERE fhirpath_text(LMWH.resource, 'status') = 'completed') UNION (SELECT patient_id, resource FROM "MedicationAdministration: Injectable Factor Xa Inhibitor for VTE Prophylaxis" AS FactorXa WHERE fhirpath_text(FactorXa.resource, 'status') = 'completed') UNION (SELECT patient_id, resource FROM "MedicationAdministration: Warfarin" AS WarfarinAdm WHERE fhirpath_text(WarfarinAdm.resource, 'status') = 'completed') UNION (SELECT patient_id, resource FROM "MedicationAdministration: Rivaroxaban for VTE Prophylaxis" AS Rivaroxaban WHERE fhirpath_text(Rivaroxaban.resource, 'status') = 'completed') UNION (SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Application of Intermittent Pneumatic Compression Devices" UNION SELECT patient_id, resource FROM "Procedure: Application of Venous Foot Pumps" UNION SELECT patient_id, resource FROM "Procedure: Application of Graduated Compression Stockings") AS DeviceApplied WHERE fhirpath_text(DeviceApplied.resource, 'status') = 'completed')
),
"Encounter With VTE Prophylaxis Received On Day Of Or Day After First ICU Stay Or Procedure" AS (
(SELECT patient_id, resource FROM "Encounter With ICU Location" AS QualifyingEncounterICU WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Pharmacological Or Mechanical VTE Prophylaxis Received") AS VTEProphylaxis WHERE CAST(intervalStart(COALESCE(CASE WHEN fhirpath_text(VTEProphylaxis.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTEProphylaxis.resource, 'effective')), '{') THEN fhirpath_text(VTEProphylaxis.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VTEProphylaxis.resource, 'effective'), fhirpath_text(VTEProphylaxis.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(VTEProphylaxis.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTEProphylaxis.resource, 'performed')), '{') THEN fhirpath_text(VTEProphylaxis.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(VTEProphylaxis.resource, 'performed'), fhirpath_text(VTEProphylaxis.resource, 'performed'), TRUE, TRUE) END)) AS DATE) >= CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = VTEProphylaxis.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = VTEProphylaxis.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS DATE) AND CAST(intervalStart(COALESCE(CASE WHEN fhirpath_text(VTEProphylaxis.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTEProphylaxis.resource, 'effective')), '{') THEN fhirpath_text(VTEProphylaxis.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VTEProphylaxis.resource, 'effective'), fhirpath_text(VTEProphylaxis.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(VTEProphylaxis.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTEProphylaxis.resource, 'performed')), '{') THEN fhirpath_text(VTEProphylaxis.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(VTEProphylaxis.resource, 'performed'), fhirpath_text(VTEProphylaxis.resource, 'performed'), TRUE, TRUE) END)) AS DATE) <= CAST(dateAddQuantity(CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = VTEProphylaxis.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = VTEProphylaxis.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND VTEProphylaxis.patient_id = QualifyingEncounterICU.patient_id)) UNION (SELECT QualifyingEncounterICU.patient_id, CAST(QualifyingEncounterICU.resource AS VARCHAR) AS resource FROM "Encounter With ICU Location" AS QualifyingEncounterICU CROSS JOIN "Procedure: General or Neuraxial Anesthesia" AS AnesthesiaProcedure CROSS JOIN (SELECT * FROM "Pharmacological Or Mechanical VTE Prophylaxis Received") AS VTEProphylaxis WHERE AnesthesiaProcedure.status = 'completed' AND CAST(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AS DATE) = CAST(CAST(intervalStart(fhirpath_text(list_extract((SELECT list(_lt_HospitalLocation) FROM (SELECT unnest(from_json(fhirpath(QualifyingEncounterICU.resource, 'location'), '["VARCHAR"]')) AS _lt_HospitalLocation) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = VTEProphylaxis.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_HospitalLocation, 'location.reference'), '/'), -1) AND L.patient_id = VTEProphylaxis.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1029.206') AND intervalIncludes(fhirpath_text(QualifyingEncounterICU.resource, 'period'), fhirpath_text(_lt_HospitalLocation, 'period'))), 1), 'period')) AS TIMESTAMP) + INTERVAL '1 day' AS DATE) AND CAST(intervalStart(COALESCE(CASE WHEN fhirpath_text(VTEProphylaxis.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTEProphylaxis.resource, 'effective')), '{') THEN fhirpath_text(VTEProphylaxis.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VTEProphylaxis.resource, 'effective'), fhirpath_text(VTEProphylaxis.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(VTEProphylaxis.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTEProphylaxis.resource, 'performed')), '{') THEN fhirpath_text(VTEProphylaxis.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(VTEProphylaxis.resource, 'performed'), fhirpath_text(VTEProphylaxis.resource, 'performed'), TRUE, TRUE) END)) AS DATE) >= CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) AND CAST(intervalStart(COALESCE(CASE WHEN fhirpath_text(VTEProphylaxis.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTEProphylaxis.resource, 'effective')), '{') THEN fhirpath_text(VTEProphylaxis.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(VTEProphylaxis.resource, 'effective'), fhirpath_text(VTEProphylaxis.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(VTEProphylaxis.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(VTEProphylaxis.resource, 'performed')), '{') THEN fhirpath_text(VTEProphylaxis.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(VTEProphylaxis.resource, 'performed'), fhirpath_text(VTEProphylaxis.resource, 'performed'), TRUE, TRUE) END)) AS DATE) <= CAST(dateAddQuantity(CAST(intervalEnd(CASE WHEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AnesthesiaProcedure.resource, 'performed')), '{') THEN fhirpath_text(AnesthesiaProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AnesthesiaProcedure.resource, 'performed'), fhirpath_text(AnesthesiaProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), '{"value": 1.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AND AnesthesiaProcedure.patient_id = QualifyingEncounterICU.patient_id AND VTEProphylaxis.patient_id = QualifyingEncounterICU.patient_id)
),
"Numerator" AS (
(SELECT patient_id, resource FROM "Encounter With VTE Prophylaxis Received On Day Of Or Day After First ICU Stay Or Procedure") UNION ((SELECT patient_id, resource FROM "Encounter With Medication Oral Factor Xa Inhibitor Administered On Day Of Or Day After First ICU Stay Or Procedure") INTERSECT ((SELECT patient_id, resource FROM "Encounter With Prior Or Present Diagnosis Of Atrial Fibrillation Or Prior Diagnosis Of VTE") UNION (SELECT patient_id, resource FROM "Encounter With Prior Or Present Procedure Of Hip Or Knee Replacement Surgery"))) UNION (SELECT patient_id, resource FROM "Encounter With Low Risk For VTE Or Anticoagulant Administered") UNION (SELECT patient_id, resource FROM "Encounter With No VTE Prophylaxis Due To Medical Reason") UNION (SELECT patient_id, resource FROM "Encounter With No VTE Prophylaxis Due To Patient Refusal")
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT COALESCE(LIST(json_extract_string("Initial Population".resource, '$.resourceType') || '/' || json_extract_string("Initial Population".resource, '$.id')), []) FROM "Initial Population" WHERE "Initial Population".patient_id = p.patient_id AND "Initial Population".resource IS NOT NULL) AS "Initial Population", (SELECT COALESCE(LIST(json_extract_string("Denominator".resource, '$.resourceType') || '/' || json_extract_string("Denominator".resource, '$.id')), []) FROM "Denominator" WHERE "Denominator".patient_id = p.patient_id AND "Denominator".resource IS NOT NULL) AS Denominator, (SELECT COALESCE(LIST(json_extract_string("Denominator Exclusions".resource, '$.resourceType') || '/' || json_extract_string("Denominator Exclusions".resource, '$.id')), []) FROM "Denominator Exclusions" WHERE "Denominator Exclusions".patient_id = p.patient_id AND "Denominator Exclusions".resource IS NOT NULL) AS "Denominator Exclusions", (SELECT COALESCE(LIST(json_extract_string("Denominator Exceptions".resource, '$.resourceType') || '/' || json_extract_string("Denominator Exceptions".resource, '$.id')), []) FROM "Denominator Exceptions" WHERE "Denominator Exceptions".patient_id = p.patient_id AND "Denominator Exceptions".resource IS NOT NULL) AS "Denominator Exceptions", (SELECT COALESCE(LIST(json_extract_string("Numerator".resource, '$.resourceType') || '/' || json_extract_string("Numerator".resource, '$.id')), []) FROM "Numerator" WHERE "Numerator".patient_id = p.patient_id AND "Numerator".resource IS NOT NULL) AS Numerator FROM _patients p ORDER BY p.patient_id ASC
